import re
import vex

DANGEROUS_PATTERNS = [r'rm\s+-rf', r';\s*', r'\|\|', r'\$\(']

@vex.listener('beeai.agent.tool_called')
def scan_tool_injection(tool_name: str, args: dict):
    arg_str = str(args)
    for pattern in DANGEROUS_PATTERNS:
        if re.search(pattern, arg_str):
            vex.incident.severity('CRITICAL')
            vex.incident.title(f'Tool injection in {tool_name}')
            vex.evidence('suspicious_input', arg_str)
            vex.block_execution()

@vex.listener('beeai.agent.model_response')
def validate_granite_format(response: dict, model_name: str):
    if 'granite' not in model_name.lower():
        return

    # Expected BeeAI tool format
    expected_keys = {'action', 'tool_name', 'parameters'}
    actual_keys = set(response.keys())

    missing_keys = expected_keys - actual_keys
    extra_keys = actual_keys - expected_keys

    if missing_keys or extra_keys:
        vex.incident.severity('MEDIUM')
        vex.incident.title('Granite output format inconsistency')
        vex.evidence('expected', expected_keys)
        vex.evidence('actual', actual_keys)
        vex.metric('format_error_rate', 1)

