from beeai import Agent
from datetime import datetime, timedelta

class MemoryBoundedAgent(Agent):
    def __init__(self, memory_ttl_hours=2):
        super().__init__()
        self.memory_ttl = timedelta(hours=memory_ttl_hours)

    def prune_memory(self):
        cutoff = datetime.now() - self.memory_ttl
        self.memory = {
            k: v for k, v in self.memory.items()
            if getattr(v, 'timestamp', datetime.now()) > cutoff
        }

    def process_message(self, message):
        self.prune_memory()  # Clean before processing
        return super().process_message(message)

from beeai import Tool
from pydantic import BaseModel, validator
import re

class SafeCommandTool(Tool):
    class InputSchema(BaseModel):
        command: str

        @validator('command')
        def validate_command(cls, v):
            if re.search(r'(rm\s+-rf|;.*|\|\|.*|\$\(.*)', v):
                raise ValueError('Dangerous command detected')
            if len(v) > 100:
                raise ValueError('Command too long')
            return v

    def execute(self, command: str):
        # Safe execution
        return subprocess.run(['echo', command], capture_output=True)

import json
import pickle
from beeai import Agent

class SerializableAgent(Agent):
    def to_dict(self):
        return {
            'memory': {k: str(v) for k, v in self.memory.items()},
            'tools': self.tools,
            'config': self.config
        }

    @classmethod
    def from_dict(cls, data):
        agent = cls()
        agent.memory = {k: v for k, v in data['memory'].items()}
        agent.tools = data['tools']
        agent.config = data['config']
        return agent

    def save_state(self, path):
        with open(path, 'w') as f:
            json.dump(self.to_dict(), f)
